import { createMuteIcon } from '@components/tests/mute';
import { createPauseIcon } from '@components/tests/pause';
import { createPlayIcon } from '@components/tests/play';
import { createVolumeIcon } from '@components/tests/volume';
import type { AnimationLibs } from '@lib/animations/animation-libs';
import type { VideoPlayer } from '@lib/video-player';
import { createSessionStorageBoolean } from '@utils/session-storage';

export type VideoControls = {
  hasSeen: boolean;
  isVisible: boolean;
  show: () => void;
  hide: () => void;
  dispose: () => void;
};

export type CreateVideoControlsOptions = {
  initialIsVisible: boolean;
  player: VideoPlayer;
  onShow?: (isFirstShow: boolean) => void;
  onHide?: () => void;
};

const hasSeenPersister = createSessionStorageBoolean('home:videoControlsHasSeen:v1');

export function createVideoControls(libs: AnimationLibs, options: CreateVideoControlsOptions): VideoControls {
  const videoControls = document.getElementById('homeVideoControls');
  const restartButton = document.getElementById('homeVideoRestart');
  const playPauseBtn = document.getElementById('homeVideoPlayPause');
  const muteBtn = document.getElementById('homeVideoMuteToggle');
  const timeDisplay = document.getElementById('homeVideoTime');
  const closeBtn = document.getElementById('homeVideoClose');
  if (!videoControls) throw new Error('Video controls element not found');
  if (!restartButton) throw new Error('Restart button element not found');
  if (!playPauseBtn) throw new Error('Play/pause button element not found');
  if (!muteBtn) throw new Error('Mute button element not found');
  if (!timeDisplay) throw new Error('Time display element not found');
  if (!closeBtn) throw new Error('Close button element not found');

  let isVisible = !!options?.initialIsVisible;
  let animationFrameId: number | null = null;
  let wasAutoPausedByScroll = false;

  const updatePlayPauseIcon = () => {
    playPauseBtn.innerHTML = options?.player.isPlaying ? createPauseIcon({ size: 18 }) : createPlayIcon({ size: 18 });
  };

  const updateMuteIcon = () => {
    muteBtn.innerHTML = options?.player.isMuted ? createMuteIcon({ size: 20 }) : createVolumeIcon({ size: 20 });
  };

  const updateTime = () => {
    if (!isVisible) return;
    const currentTime = options?.player.video.currentTime;
    const minutes = Math.floor(currentTime / 60);
    const seconds = Math.floor(currentTime % 60);
    timeDisplay.textContent = `${minutes.toString().padStart(2, '0')}:${seconds.toString().padStart(2, '0')}`;
    animationFrameId = requestAnimationFrame(updateTime);
  };

  const startTimeUpdate = () => {
    if (animationFrameId !== null) return;
    updateTime();
  };

  const stopTimeUpdate = () => {
    if (animationFrameId === null) return;
    cancelAnimationFrame(animationFrameId);
    animationFrameId = null;
  };

  const handleRestart = () => {
    options?.player.restart();
    wasAutoPausedByScroll = false;
    updatePlayPauseIcon();
  };

  const handleSkipBackward = () => {
    if (!options?.player?.video) return;
    const newTime = Math.max(0, options.player.video.currentTime - 10);
    options.player.video.currentTime = newTime;
  };

  const handleSkipForward = () => {
    if (!options?.player?.video) return;
    const duration = options.player.video.duration || 0;
    const newTime = Math.min(duration, options.player.video.currentTime + 10);
    options.player.video.currentTime = newTime;
  };

  const handlePlayPause = () => {
    wasAutoPausedByScroll = false;
    options?.player.togglePlayPause();
    updatePlayPauseIcon();
  };

  const handleMute = () => {
    options?.player.toggleMute();
    updateMuteIcon();
  };

  const handleKeyboard = (event: KeyboardEvent) => {
    if (event.metaKey || event.ctrlKey || event.altKey) return;
    const handledCodes = new Set(['Space', 'Escape', 'KeyR', 'ArrowLeft', 'ArrowRight', 'KeyM']);
    if (!handledCodes.has(event.code)) return;
    event.preventDefault();
    switch (event.code) {
      case 'Space':
        return handlePlayPause();
      case 'Escape':
        return hide();
      case 'KeyR':
        return handleRestart();
      case 'ArrowLeft':
        return handleSkipBackward();
      case 'ArrowRight':
        return handleSkipForward();
      case 'KeyM':
        return handleMute();
      default:
    }
  };

  const show = () => {
    if (isVisible) return;
    isVisible = true;
    const vh = window.innerHeight;
    libs.gsap.fromTo(
      videoControls,
      {
        opacity: 0,
        y: vh * 0.1
      },
      {
        opacity: 1,
        y: 0,
        pointerEvents: 'auto',
        duration: 0.3,
        ease: 'power2.inOut'
      }
    );
    const hasSeen = hasSeenPersister.get();
    options?.onShow?.(!hasSeen);
    hasSeenPersister.set(true);
    startTimeUpdate();
    document.addEventListener('keydown', handleKeyboard);
  };

  const hide = () => {
    if (!isVisible) return;
    isVisible = false;
    const vh = window.innerHeight;
    libs.gsap.to(videoControls, {
      opacity: 0,
      y: vh * 0.1,
      pointerEvents: 'none',
      duration: 0.3,
      ease: 'power2.inOut'
    });
    options?.onHide?.();
    stopTimeUpdate();
    document.removeEventListener('keydown', handleKeyboard);
  };

  const checkVideoPosition = () => {
    const rect = options.player.video.getBoundingClientRect();
    const viewportHeight = window.innerHeight;
    const videoBottom = rect.bottom;
    const threshold = viewportHeight * 0.8;
    if (videoBottom < threshold) {
      hide();
      if (options.player.isPlaying) {
        wasAutoPausedByScroll = true;
        options.player.pause();
      }
    } else if (wasAutoPausedByScroll && !options.player.isPlaying) {
      options.player.play();
      wasAutoPausedByScroll = false;
    }
  };

  updateMuteIcon();
  updatePlayPauseIcon();
  restartButton.addEventListener('click', handleRestart);
  playPauseBtn.addEventListener('click', handlePlayPause);
  muteBtn.addEventListener('click', handleMute);
  closeBtn.addEventListener('click', hide);
  options?.player.video.addEventListener('play', updatePlayPauseIcon);
  options?.player.video.addEventListener('pause', updatePlayPauseIcon);
  options?.player.video.addEventListener('volumechange', updateMuteIcon);
  window.addEventListener('scroll', checkVideoPosition, { passive: true });

  return {
    get isVisible() {
      return isVisible;
    },
    get hasSeen() {
      return hasSeenPersister.get();
    },
    hide,
    show,
    dispose: () => {
      stopTimeUpdate();
      document.removeEventListener('keydown', handleKeyboard);
      window.removeEventListener('scroll', checkVideoPosition);
      restartButton.removeEventListener('click', handleRestart);
      playPauseBtn.removeEventListener('click', handlePlayPause);
      muteBtn.removeEventListener('click', handleMute);
      closeBtn.removeEventListener('click', hide);
      options?.player.video.removeEventListener('play', updatePlayPauseIcon);
      options?.player.video.removeEventListener('pause', updatePlayPauseIcon);
      options?.player.video.removeEventListener('volumechange', updateMuteIcon);
    }
  };
}
